// SPDX-License-Identifier: MIT
pragma solidity 0.8.20;

contract TokenVoting {
    address public owner;
    uint256 public candidateCount;

    struct Candidate {
        uint256 id;
        string name;
        uint256 voteCount;
    }

    mapping(uint256 => Candidate) public candidates;
    mapping(address => bool) public hasVotingRights;
    mapping(address => bool) public hasVoted;

    event CandidateAdded(uint256 indexed candidateId, string name);
    event VotingRightsGranted(address indexed voter);
    event VoteCast(address indexed voter, uint256 indexed candidateId);

    modifier onlyOwner() {
        require(msg.sender == owner, "Only owner can call this function");
        _;
    }

    constructor() {
        owner = msg.sender;
        candidateCount = 0;
    }

    function addCandidate(string memory name) external onlyOwner {
        candidateCount++;
        candidates[candidateCount] = Candidate({
            id: candidateCount,
            name: name,
            voteCount: 0
        });
        emit CandidateAdded(candidateCount, name);
    }

    function grantVotingRights(address voter) external onlyOwner {
        require(voter != address(0), "Invalid address");
        require(!hasVotingRights[voter], "Already has voting rights");

        hasVotingRights[voter] = true;
        emit VotingRightsGranted(voter);
    }

    function vote(uint256 candidateId) external {
        require(hasVotingRights[msg.sender], "No voting rights");
        require(!hasVoted[msg.sender], "Already voted");
        require(candidateId > 0 && candidateId <= candidateCount, "Invalid candidate ID");

        hasVoted[msg.sender] = true;
        candidates[candidateId].voteCount++;

        emit VoteCast(msg.sender, candidateId);
    }

    function candidateNames(uint256 candidateId) external view returns (string memory) {
        require(candidateId > 0 && candidateId <= candidateCount, "Invalid candidate ID");
        return candidates[candidateId].name;
    }

    function candidateVotes(uint256 candidateId) external view returns (uint256) {
        require(candidateId > 0 && candidateId <= candidateCount, "Invalid candidate ID");
        return candidates[candidateId].voteCount;
    }
}
